import{_ as e,o as i,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const r="/media/202507/2025-07-29_163839_0376990.0007209118432673911.png",p="/media/202508/2025-08-21_192059_9358860.5911447368528479.png",o="/media/202507/2025-07-29_190539_7844830.6991171186085761.png",n="/media/202507/2025-07-29_191303_9113110.9890031402784571.png",h="/media/202507/2025-07-29_201151_0867210.12699631667674804.png",s="/media/202507/2025-07-31_153547_8965810.13640006126523685.png",I=JSON.parse('{"title":"AIUI 服务链路介绍","description":"","frontmatter":{"title":"AIUI 服务链路介绍"},"headers":[],"relativePath":"platform-service/service-chain.md","filePath":"platform-service/service-chain.md","lastUpdated":null}'),c={name:"platform-service/service-chain.md"};function u(d,a,_,m,x,f){return i(),t("div",null,[...a[0]||(a[0]=[l('<p>AIUI服务链路概述</p><p>AIUI平台针对语义交互场景，目前提供三种服务链路，按照服务能力支持的时间先后顺序分别为：</p><h2 id="传统语义交互链路" tabindex="-1">传统语义交互链路 <a class="header-anchor" href="#传统语义交互链路" aria-label="Permalink to &quot;传统语义交互链路&quot;">​</a></h2><p>传统语义交互链路是AIUI平台2016底开始推出的，以传统语义理解能力为核心，为人机交互方案提供结构化服务结果。 其中结构化语义理解主要采用语法句式匹配的技术方案，其支持配置的能力项有：</p><ul><li>商店技能</li><li>自定义技能</li><li>语句问答</li><li>关键词问答</li><li>设备人设</li><li>闲聊兜底</li></ul><h3 id="_1-1-应用配置" tabindex="-1">1.1. 应用配置 <a class="header-anchor" href="#_1-1-应用配置" aria-label="Permalink to &quot;1.1. 应用配置&quot;">​</a></h3><p>在老AIUI应用配置中开启结构化语义</p><p>温馨提示</p><p>传统语义链路不可以开启大模型配置。关于新老应用说明，见文档<a href="https://aiui-doc-admin.xf-yun.com/project-14/doc-604/" target="_blank" rel="noreferrer">【AIUI应用介绍】</a>说明。</p><p><img src="'+r+'" alt="" title="null"></p><h3 id="_1-2-流程说明" tabindex="-1">1.2. 流程说明 <a class="header-anchor" href="#_1-2-流程说明" aria-label="Permalink to &quot;1.2. 流程说明&quot;">​</a></h3><p>传统语义链路云服务支持能力有：语音识别、结构化语义、应用后处理、语音合成能力，其全能力服务流程为：</p><p><strong>语音识别 → 结构化语义 → 后处理 → 语音合成</strong></p><p>该流程顺序固定，除语音识别外的其他模块可开关，且配置修改时按照整体流程插入或移除处理项。 下面为AIUI传统语义链路全能力适配的服务流程图：</p><p><img src="'+p+'" alt="" title="null"></p><p>如上图所示，云端开启后处理+语音合成全链路能力时，后处理服务接受AIUI云服务转发的语义结果做业务处理，然后返回结果给到AIUI,然后语音合成服务从接受到的后处理结果中提取合成文本做合成处理。</p><p><strong>技能优先级说明：</strong></p><ul><li>自定义技能 &gt; 语句问答 &gt; 设备人设 &gt; 商店技能 &gt; 关键词问答 &gt; 兜底闲聊</li><li>同类型技能不区分优先级。</li></ul><h3 id="注意" tabindex="-1">注意： <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意：&quot;">​</a></h3><p>全链路使用时，语音合成服务是从后处理结果的 answer.text 字段中提取合成文本的。所以在配置应用后处理+语音合成场景下，后处理返回的结果需要满足下面的格式：</p><p>{&quot;intent&quot; : { &quot;answer&quot; : {&quot;text&quot;:&quot;xxxx&quot;}}}</p><h3 id="_1-3-接入说明" tabindex="-1">1.3. 接入说明 <a class="header-anchor" href="#_1-3-接入说明" aria-label="Permalink to &quot;1.3. 接入说明&quot;">​</a></h3><p>传统语义交互链路SDK和API开发接入说明如下：</p><ul><li>SDK接入：</li></ul><p>SDK支持版本说明:</p><p>**-- 5.xxx 版本，直接对接</p><p>-- 6.xxx 及以上版本，aiui.cfg中需配置aiui_ver参数取值为1**</p><p>开发详见 <a href="/sdk-dev/classic-chain/">【SDK开发接入 - 传统语义链路】</a>文档说明</p><ul><li>API接入：</li></ul><p>开发详见 <a href="/api-dev/classic-chain/">【API开发接入 - 传统语义链路】</a>文档说明</p><p>本协议为会话级短连接：一次会话结束后即断开连接</p><h2 id="通用大模型交互链路" tabindex="-1">通用大模型交互链路 <a class="header-anchor" href="#通用大模型交互链路" aria-label="Permalink to &quot;通用大模型交互链路&quot;">​</a></h2><h3 id="_2-1-应用配置" tabindex="-1">2.1. 应用配置 <a class="header-anchor" href="#_2-1-应用配置" aria-label="Permalink to &quot;2.1. 应用配置&quot;">​</a></h3><p>传统语义和大模型语义主要区别在于是否开启“大模型”。开启大模型配置后，此时应用服务配置指向到通用大模型链路授权。</p><p><img src="'+o+'" alt="" title="null"></p><h3 id="注意-1" tabindex="-1">注意： <a class="header-anchor" href="#注意-1" aria-label="Permalink to &quot;注意：&quot;">​</a></h3><p>老应用未进行授权时，可以任意切换服务链路。但是当应用有过传统语义链路授权后，大模型能力将不再支持随意开关。关闭后再开启会提示“您的应用为正式授权过通用语义模型的应用，若想使用交互大模型Lite版请联系商务。”</p><p><img src="'+n+'" alt="" title="null"></p><h3 id="_2-2-流程说明" tabindex="-1">2.2. 流程说明 <a class="header-anchor" href="#_2-2-流程说明" aria-label="Permalink to &quot;2.2. 流程说明&quot;">​</a></h3><p>通用大模型交互链路不是仅仅在传统语义交互链路后面用大模型替代闲聊兜底能力，而是基于语义理解需求，服务层面通过级联方式，添加如：语义规整、意图落域、知识分类、智能体、文档问答、联网搜索、兜底大模型等各种能力组合而成。</p><p>下面为通用大模型交互链路服务流程图：</p><h3 id="_2-3-接入说明" tabindex="-1">2.3. 接入说明 <a class="header-anchor" href="#_2-3-接入说明" aria-label="Permalink to &quot;2.3. 接入说明&quot;">​</a></h3><p>通用大模型交互链路SDK和API开发接入说明如下：</p><ul><li>SDK接入：</li></ul><p>SDK支持版本说明:</p><p>**-- 5.xxx 版本，不支持</p><p>-- 6.xxx 及以上版本，aiui.cfg中需配置aiui_ver参数取值为2**</p><p>开发详见 <a href="/sdk-dev/llm-chain/">【SDK开发接入 - 通用大模型链路】</a>文档说明</p><ul><li>API接入：</li></ul><p>开发详见 <a href="/api-dev/llm-chain/">【API开发接入 - 通用大模型链路】</a>文档说明</p><p>本协议为长连接交互协议：支持一次链接进行长时间多次对话</p><h2 id="极速超拟人交互链路" tabindex="-1">极速超拟人交互链路 <a class="header-anchor" href="#极速超拟人交互链路" aria-label="Permalink to &quot;极速超拟人交互链路&quot;">​</a></h2><h3 id="_3-1-应用配置" tabindex="-1">3.1. 应用配置 <a class="header-anchor" href="#_3-1-应用配置" aria-label="Permalink to &quot;3.1. 应用配置&quot;">​</a></h3><p>极速超拟人交互链路是强绑定在AIUI新应用下的，链路固定开启，任何配置修改都不改变服务链路类型。</p><p><img src="'+h+'" alt="" title="null"></p><h3 id="_3-2-流程说明" tabindex="-1">3.2. 流程说明 <a class="header-anchor" href="#_3-2-流程说明" aria-label="Permalink to &quot;3.2. 流程说明&quot;">​</a></h3><p>极速超拟人交互链路是通用大模型链路基础上的升级版本。服务流程链路和通用大模型基本保持一致，在功能方面针对如智能体、兜底大模型、设备人设能力方面做了更多的开放，例如智能体支持三方平台接入、支持编排和结果输出，兜底大模型支持开发者自行选配，也支持符合OpenAI API协议的三方大模型配置转发等。 下面为极速超拟人交互链路服务流程图：</p><p><img src="'+s+'" alt="" title="null"></p><h3 id="_3-3-接入说明" tabindex="-1">3.3. 接入说明 <a class="header-anchor" href="#_3-3-接入说明" aria-label="Permalink to &quot;3.3. 接入说明&quot;">​</a></h3><p>极速超拟人交互链路SDK和API开发接入说明如下：</p><p>极速超拟人交互链路SDK和API开发接入说明如下：</p><ul><li>SDK接入：</li></ul><p>SDK支持版本说明:</p><p>**-- 5.xxx 版本，不支持</p><p>-- 6.8.xxx 及以上版本，aiui.cfg中需配置aiui_ver参数取值为3**</p><p>开发详见 <a href="/sdk-dev/ultra-chain/">【SDK开发接入 - 极速超拟人链路】</a>文档说明</p><ul><li>API接入：</li></ul><p>开发详见 <a href="/api-dev/ultra-chain/">【API开发接入 - 极速超拟人链路】</a>文档说明</p><p>本协议也为长连接交互协议：支持一次链接进行长时间多次对话</p>',69)])])}const b=e(c,[["render",u]]);export{I as __pageData,b as default};
